const body = $input.first().json.body || $input.first().json;

const ticketId = body.ticketId;
const agentName = body.agentName;
const adapterType = body.adapterType;
const failureReason = body.failureReason || '';
const errorOutput = body.errorOutput || '';

if (!ticketId || !agentName || !adapterType) {
  return [{
    json: {
      valid: false,
      error: 'Missing required fields: ticketId, agentName, adapterType'
    }
  }];
}

const RATE_LIMIT_PATTERNS = [
  /rate.?limit/i,
  /overloaded/i,
  /too many requests/i,
  /429/,
  /RESOURCE_EXHAUSTED/i,
  /quota.?exceeded/i,
  /capacity/i,
  /usage.?limit/i,
  /weekly.?limit/i,
  /throttl/i
];

const combined = failureReason + ' ' + errorOutput;
const isRateLimited = RATE_LIMIT_PATTERNS.some(p => p.test(combined));

return [{
  json: {
    valid: true,
    isRateLimited,
    ticketId,
    agentName,
    adapterType,
    failureReason,
    errorOutput,
    detectedAt: new Date().toISOString()
  }
}];

const input = $('Validate and Detect').first().json;

const PROVIDER_CHAIN = {
  claude_local: ['cursor', 'codex_local', 'gemini_local'],
  codex_local: ['cursor', 'claude_local', 'gemini_local'],
  gemini_local: ['cursor', 'codex_local', 'claude_local'],
  cursor: ['codex_local', 'claude_local', 'gemini_local'],
};

const EXCLUDED_FROM_FAILOVER = ['atlas', 'nora'];

const CAPABILITY_GROUPS = {
  implementation: {
    cursor: ['neo', 'luna', 'lars', 'max', 'rio', 'quinn', 'remi', 'helix', 'vega', 'cursor-engineer-failover'],
    codex_local: ['dana', 'finn', 'eli'],
    claude_local: [],
    gemini_local: [],
  },
  security_audit: {
    cursor: ['sentinel', 'argus', 'cursor-security-failover'],
    codex_local: ['eli'],
    claude_local: [],
    gemini_local: [],
  },
  devops: {
    codex_local: ['zara', 'finn'],
    cursor: ['vera', 'cursor-engineer-failover'],
    claude_local: [],
    gemini_local: [],
  },
  research: {
    cursor: ['scout', 'cursor-analyst-failover', 'vera'],
    codex_local: ['sage', 'eli'],
    claude_local: [],
    gemini_local: [],
  },
  product_qa: {
    cursor: ['vera', 'nora', 'quinn'],
    codex_local: ['sage', 'eli'],
    claude_local: [],
    gemini_local: [],
  },
  recruiting: {
    codex_local: ['aria'],
    cursor: ['vera'],
    claude_local: [],
    gemini_local: [],
  },
  retrospective: {
    cursor: ['nova', 'helix'],
    codex_local: ['aria'],
    claude_local: [],
    gemini_local: [],
  },
};

if (EXCLUDED_FROM_FAILOVER.includes(input.agentName)) {
  return [{
    json: {
      action: 'escalate',
      reason: 'Agent ' + input.agentName + ' is excluded from auto-failover (strategic role)',
      ticketId: input.ticketId,
      agentName: input.agentName,
      adapterType: input.adapterType,
      fallbackAgent: null,
      fallbackProvider: null,
    },
  }];
}

let agentGroup = null;
for (const [group, providers] of Object.entries(CAPABILITY_GROUPS)) {
  for (const agents of Object.values(providers)) {
    if (agents.includes(input.agentName)) {
      agentGroup = group;
      break;
    }
  }
  if (agentGroup) break;
}

if (!agentGroup) {
  return [{
    json: {
      action: 'escalate',
      reason: 'Agent ' + input.agentName + ' not found in any capability group',
      ticketId: input.ticketId,
      agentName: input.agentName,
      adapterType: input.adapterType,
      fallbackAgent: null,
      fallbackProvider: null,
    },
  }];
}

const chain = PROVIDER_CHAIN[input.adapterType] || ['cursor', 'codex_local'];
let fallbackAgent = null;
let fallbackProvider = null;

for (const nextProvider of chain) {
  const candidates = (CAPABILITY_GROUPS[agentGroup] || {})[nextProvider] || [];
  const filtered = candidates.filter(candidate => candidate !== input.agentName);
  if (filtered.length > 0) {
    fallbackAgent = filtered[0];
    fallbackProvider = nextProvider;
    break;
  }
}

if (!fallbackAgent) {
  return [{
    json: {
      action: 'escalate',
      reason: 'No fallback agent available for group ' + agentGroup + ' across providers: ' + chain.join(', '),
      ticketId: input.ticketId,
      agentName: input.agentName,
      adapterType: input.adapterType,
      fallbackAgent: null,
      fallbackProvider: null,
    },
  }];
}

return [{
  json: {
    action: 'reassign',
    ticketId: input.ticketId,
    agentName: input.agentName,
    adapterType: input.adapterType,
    fallbackAgent,
    fallbackProvider,
    capabilityGroup: agentGroup,
    detectedAt: input.detectedAt,
  },
}];

const input = $('Validate and Detect').first().json;

return [{
  json: {
    action: 'skipped',
    reason: !input.valid ? input.error : 'Failure is not a rate limit — standard error handling applies',
    ticketId: input.ticketId || null,
    agentName: input.agentName || null,
    adapterType: input.adapterType || null,
    fallbackAgent: null,
    fallbackProvider: null
  }
}];

let upstream;
try {
  upstream = $('Notify Reassignment').first().json;
} catch (e) {
  try {
    upstream = $('Notify Escalation').first().json;
  } catch (e2) {
    try {
      upstream = $('Not Rate Limited').first().json;
    } catch (e3) {
      upstream = { action: 'error', reason: 'Could not resolve upstream result' };
    }
  }
}

const resolve = (() => {
  try { return $('Resolve Fallback').first().json; } catch (e) { return null; }
})();
const validate = (() => {
  try { return $('Validate and Detect').first().json; } catch (e) { return null; }
})();

const action = (resolve && resolve.action) || (validate && !validate.valid ? 'invalid' : 'skipped');

return [{
  json: {
    workflow: 'hive-rate-limit-failover',
    endpoint: 'rate-limit-failover',
    kind: 'deterministic',
    status: 'completed',
    receivedAt: (validate && validate.detectedAt) || new Date().toISOString(),
    timeoutMs: 30000,
    success: true,
    result: {
      action,
      ticketId: (resolve && resolve.ticketId) || (validate && validate.ticketId) || null,
      originalAgent: (resolve && resolve.agentName) || (validate && validate.agentName) || null,
      originalProvider: (resolve && resolve.adapterType) || (validate && validate.adapterType) || null,
      fallbackAgent: resolve && resolve.fallbackAgent,
      fallbackProvider: resolve && resolve.fallbackProvider,
      capabilityGroup: resolve && resolve.capabilityGroup,
      reason: (resolve && resolve.reason) || null
    }
  }
}];
